#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
typedef long long ll;
inline ll read()
{
	ll res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=5e5+10,B=60,Mod=998244353;
int f[N][61][2],dp[N],n,g[61][2];ll a[N];vector<int> T[N];
inline void DN(int &x){x>=Mod?x-=Mod:0;}
int main()
{
	n=read();rep(1,n,i)a[i]=read();
	rep(2,n,i)T[read()].push_back(i);
	drep(n,1,u)
	{
		rep(0,B,i)++f[u][i][a[u]>>i&1];dp[u]=0;
		for(int v:T[u])
		{
			rep(0,B,i)rep(0,1,bu)rep(0,1,bv)g[i][bu^bv]=(1ll*f[u][i][bu]*f[v][i][bv]+g[i][bu^bv])%Mod;
			memcpy(f[u],g,sizeof(g));memset(g,0,sizeof(g));
		}
		rep(0,B,i)dp[u]=((1ll<<i)%Mod*f[u][i][1]+dp[u])%Mod;
		rep(0,B,i)DN(f[u][i][0]+=dp[u]);
	}
	printf("%d\n",dp[1]);
}
